(function(){
  const panel=document.querySelector('[data-command-panel]');
  const input=document.querySelector('[data-command-input]');
  const results=document.querySelector('[data-command-results]');
  function rootPath(){ if(location.pathname.includes('/volumes/')) return '../../'; if(location.pathname.includes('/modules/')) return '../'; return ''; }
  function openPanel(){ if(!panel) return; panel.hidden=false; input&&input.focus(); render(''); }
  function closePanel(){ if(panel) panel.hidden=true; }
  function render(q){ if(!results) return; const query=(q||'').toLowerCase().trim(); const hits=SEARCH_INDEX.filter(x=>!query||x.title.toLowerCase().includes(query)||x.desc.toLowerCase().includes(query)||x.type.toLowerCase().includes(query)).slice(0,18); results.innerHTML=hits.map(h=>`<a href="${rootPath()}${h.url}"><b>${h.title}</b><br><small>${h.type} · ${h.desc}</small></a>`).join('') || '<p class="muted">No results.</p>'; }
  document.addEventListener('click',e=>{ if(e.target.matches('[data-open-command]')) openPanel(); if(e.target.matches('[data-close-command]')) closePanel(); });
  document.addEventListener('keydown',e=>{ if((e.metaKey||e.ctrlKey)&&e.key.toLowerCase()==='k'){ e.preventDefault(); openPanel(); } if(e.key==='Escape') closePanel(); });
  input&&input.addEventListener('input',e=>render(e.target.value));
  document.querySelectorAll('[data-expand-all]').forEach(btn=>btn.addEventListener('click',()=>document.querySelectorAll('details').forEach(d=>d.open=true)));
  document.querySelectorAll('[data-collapse-all]').forEach(btn=>btn.addEventListener('click',()=>document.querySelectorAll('details').forEach(d=>d.open=false)));
  document.querySelectorAll('pre').forEach(pre=>{ const b=document.createElement('button'); b.textContent='Copy'; b.className='btn copy'; b.style.marginBottom='8px'; b.addEventListener('click',()=>navigator.clipboard&&navigator.clipboard.writeText(pre.innerText)); pre.parentNode.insertBefore(b,pre); });
  if(location.hash) setTimeout(()=>{ const el=document.querySelector(location.hash); if(el&&el.tagName==='DETAILS') el.open=true; },100);
})();